mapper.insert:
insert into userlog(userId, type, operationTime, reserveTime
,comment)
values (#{userId}, #{type}, #{operationTime}, #{reserveTime}
,
#{comment});

mapper.select:
select *
from userlog


        and type like concat('%',
        #{type},
        '%'
        )


        and operationTime >=
        #{date_min}


        and operationTime <=
        #{date_max}


        and comment like concat('%',
        #{comment},
        '%'
        )


;
